public String html() {
    StringBuilder accum = new StringBuilder();
    html(accum);
    String result = accum.toString();
    // Trim only if the result does not start or end with '<' indicating it's not part of an HTML tag
    if (!result.isEmpty() && !result.startsWith("<") && !result.endsWith(">")) {
        result = result.trim();
    }
    return result;
}
